from flask import Flask, request, jsonify, g
import logging
import json
import os
from datetime import datetime
import traceback

app = Flask(__name__)

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    handlers=[
        logging.FileHandler('app.log'),
        logging.StreamHandler()
    ]
)

logger = logging.getLogger(__name__)

# Middleware to log all requests
@app.before_request
def log_request_info():
    g.start_time = datetime.now()
    logger.info(f"REQUEST: {request.method} {request.url}")
    logger.info(f"HEADERS: {dict(request.headers)}")
    
    if request.is_json:
        logger.info(f"BODY: {request.get_json()}")
    elif request.form:
        logger.info(f"FORM DATA: {dict(request.form)}")
    elif request.data:
        logger.info(f"RAW DATA: {request.data.decode('utf-8')}")

# Middleware to log all responses
@app.after_request
def log_response_info(response):
    duration = datetime.now() - g.start_time
    logger.info(f"RESPONSE: {response.status_code} - Duration: {duration}")
    logger.info(f"RESPONSE DATA: {response.get_data(as_text=True)}")
    return response

# Error handling with logging
@app.errorhandler(Exception)
def handle_exception(e):
    logger.error(f"UNCAUGHT EXCEPTION: {str(e)}")
    logger.error(f"TRACEBACK: {traceback.format_exc()}")
    return jsonify({"error": "Internal server error"}), 500

