# Protected endpoint with user information logging
@app.route('/protected', methods=['GET'])
def protected():
    try:
        auth_header = request.headers.get('Authorization')
        logger.info(f"PROTECTED ACCESS - Authorization: {auth_header}")
        
        if not auth_header or not auth_header.startswith('Bearer '):
            logger.warning("MISSING OR INVALID AUTHORIZATION")
            return jsonify({"error": "Missing or invalid authorization"}), 401
            
        token = auth_header.split(' ')[1]
        logger.info(f"PROTECTED ACCESS - Token: {token}")
        
        # Simulate token validation
        if token == 'fake-jwt-token':
            return jsonify({"message": "Access granted", "user": "admin"})
        else:
            logger.warning("INVALID TOKEN ACCESS ATTEMPT")
            return jsonify({"error": "Invalid token"}), 401
            
    except Exception as e:
        logger.error(f"PROTECTED ENDPOINT ERROR: {str(e)}")
        logger.error(f"PROTECTED TRACEBACK: {traceback.format_exc()}")
        return jsonify({"error": "Access denied"}), 500

